<?php require '_header.php'; $items=read_json('projects'); if(isset($_GET['delete'])){ $items=array_values(array_filter($items,fn($x)=>$x['slug']!==$_GET['delete'])); write_json('projects',$items); header('Location: projects.php'); exit; } ?><div class="admin-head"><h1>Projects</h1><a class="btn primary" href="project-form.php">Add Project</a></div><table class="admin-table"><tr><th>Title</th><th>Category</th><th>Status</th><th>Actions</th></tr><?php foreach($items as $x): ?><tr><td><?=e($x['title'])?></td><td><?=e($x['category'])?></td><td><?=e($x['status'])?></td><td><a href="project-form.php?slug=<?=e($x['slug'])?>">Edit</a> | <a onclick="return confirm('Delete project?')" href="projects.php?delete=<?=e($x['slug'])?>">Delete</a></td></tr><?php endforeach; ?></table><?php require '_footer.php'; ?>
